9239     SmallVector<int> Mask;
9240     return TE->State == TreeEntry::NeedToGather &&
9241            !any_of(TE->Scalars,
9242                    [this](Value *V) { return EphValues.contains(V); }) &&
9243            (allConstant(TE->Scalars) || isSplat(TE->Scalars) ||
9244             TE->Scalars.size() < Limit ||
9245             ((TE->getOpcode() == Instruction::ExtractElement ||
9246               all_of(TE->Scalars, IsaPred<ExtractElementInst, UndefValue>)) &&
9247              isFixedVectorShuffle(TE->Scalars, Mask)) ||
9248             (TE->State == TreeEntry::NeedToGather &&
9249              TE->getOpcode() == Instruction::Load && !TE->isAltShuffle()));
9250   };
9251 
9252   // We only handle trees of heights 1 and 2.
9253   if (VectorizableTree.size() == 1 &&
9254       (VectorizableTree[0]->State == TreeEntry::Vectorize ||
9255        (ForReduction &&
9256         AreVectorizableGathers(VectorizableTree[0].get(),
9257                                VectorizableTree[0]->Scalars.size()) &&
9258         VectorizableTree[0]->getVectorFactor() > 2)))
9259     return true;
9260 
9261   if (VectorizableTree.size() != 2)
9262     return false;
9263 
