9265   // with the second gather nodes if they have less scalar operands rather than
9266   // the initial tree element (may be profitable to shuffle the second gather)
9267   // or they are extractelements, which form shuffle.
9268   SmallVector<int> Mask;
9269   if (VectorizableTree[0]->State == TreeEntry::Vectorize &&
9270       AreVectorizableGathers(VectorizableTree[1].get(),
9271                              VectorizableTree[0]->Scalars.size()))
9272     return true;
9273 
9274   // Gathering cost would be too much for tiny trees.
9275   if (VectorizableTree[0]->State == TreeEntry::NeedToGather ||
9276       (VectorizableTree[1]->State == TreeEntry::NeedToGather &&
9277        VectorizableTree[0]->State != TreeEntry::ScatterVectorize &&
9278        VectorizableTree[0]->State != TreeEntry::StridedVectorize))
9279     return false;
9280 
9281   return true;
9282 }
