9284 static bool isLoadCombineCandidateImpl(Value *Root, unsigned NumElts,
9285                                        TargetTransformInfo *TTI,
9286                                        bool MustMatchOrInst) {
9287   // Look past the root to find a source value. Arbitrarily follow the
9288   // path through operand 0 of any 'or'. Also, peek through optional
9289   // shift-left-by-multiple-of-8-bits.
9290   Value *ZextLoad = Root;
9291   const APInt *ShAmtC;
9292   bool FoundOr = false;
9293   while (!isa<ConstantExpr>(ZextLoad) &&
9294          (match(ZextLoad, m_Or(m_Value(), m_Value())) ||
9295           (match(ZextLoad, m_Shl(m_Value(), m_APInt(ShAmtC))) &&
9296            ShAmtC->urem(8) == 0))) {
9297     auto *BinOp = cast<BinaryOperator>(ZextLoad);
9298     ZextLoad = BinOp->getOperand(0);
9299     if (BinOp->getOpcode() == Instruction::Or)
9300       FoundOr = true;
9301   }
9302   // Check if the input is an extended load of the required or/shift expression.
9303   Value *Load;
9304   if ((MustMatchOrInst && !FoundOr) || ZextLoad == Root ||
9305       !match(ZextLoad, m_ZExt(m_Value(Load))) || !isa<LoadInst>(Load))
9306     return false;
9307 
9308   // Require that the total load bit width is a legal integer type.
9309   // For example, <8 x i8> --> i64 is a legal integer on a 64-bit target.
9310   // But <16 x i8> --> i128 is not, so the backend probably can't reduce it.
9311   Type *SrcTy = Load->getType();
9312   unsigned LoadBitWidth = SrcTy->getIntegerBitWidth() * NumElts;
9313   if (!TTI->isTypeLegal(IntegerType::get(Root->getContext(), LoadBitWidth)))
9314     return false;
9315 
9316   // Everything matched - assume that we can fold the whole sequence using
9317   // load combining.
9318   LLVM_DEBUG(dbgs() << "SLP: Assume load combining for tree starting at "
9319              << *(cast<Instruction>(Root)) << "\n");
